/* Remonte workout engine — pure functions over the offline exercise database.
   Generates a time-boxed, full-body gym/home workout from a seed, so a planned
   session reproduces deterministically without persisting its structure. */

export const CATEGORIES = ["warmup", "lower", "upperPush", "upperPull", "core", "cardio", "mobility"];

export const CATEGORY_LABELS = {
  warmup: "Warm-up", lower: "Lower body", upperPush: "Upper push", upperPull: "Upper pull",
  core: "Core", cardio: "Cardio", mobility: "Mobility",
};

export const EQUIPMENT_LABELS = {
  mat: "Yoga mat", bands: "Resistance band", dumbbells: "Dumbbells", kettlebell: "Kettlebell",
  pullupBar: "Pull-up bar", foamRoller: "Foam roller", jumpRope: "Jump rope", bench: "Bench / step",
  wallBall: "Wall ball", trx: "Suspension (TRX)",
  barbell: "Barbell", cable: "Cable", machine: "Machine", smith: "Smith machine",
  legPress: "Leg press", latPulldown: "Lat pulldown", rower: "Rower", "bike-erg": "Bike erg",
  ezbar: "EZ bar", plate: "Weight plate",
};

/* The home-equipment keys a user can own; gym venue ignores this filter. */
export const HOME_EQUIPMENT = ["mat", "bands", "dumbbells", "kettlebell", "pullupBar", "foamRoller", "jumpRope", "bench", "wallBall", "trx"];

/* Duration → ordered category slots [category, count]. Every template carries
   lower + an upper + core, so each session is full-body. */
export const GYM_TEMPLATES = {
  30: [["warmup", 1], ["lower", 1], ["upperPush", 1], ["core", 1], ["mobility", 1]],
  45: [["warmup", 1], ["lower", 1], ["upperPush", 1], ["upperPull", 1], ["core", 1], ["cardio", 1], ["mobility", 1]],
  60: [["warmup", 1], ["lower", 2], ["upperPush", 1], ["upperPull", 1], ["core", 1], ["cardio", 1], ["mobility", 1]],
  75: [["warmup", 1], ["lower", 2], ["upperPush", 2], ["upperPull", 1], ["core", 2], ["cardio", 1], ["mobility", 1]],
  90: [["warmup", 1], ["lower", 2], ["upperPush", 2], ["upperPull", 2], ["core", 2], ["cardio", 2], ["mobility", 1]],
};
const GYM_DURATIONS = Object.keys(GYM_TEMPLATES).map(Number);

const byId = new Map(EXERCISES.map(e => [e.id, e]));
export function exerciseById(id) { return byId.get(id) || null; }

/* Exercises eligible for a venue: home filters by owned equipment, gym has all.
   Banned ids are always excluded. */
export function filterEligible({ venue = "home", equipment = {}, banned = [] }) {
  const ban = new Set(banned);
  return EXERCISES.filter(e => {
    if (ban.has(e.id)) return false;
    if (!e.venues.includes(venue)) return false;
    if (venue === "home") return e.equipment.every(k => equipment[k]);
    return true;
  });
}

/* Small seeded PRNG (mulberry32) — deterministic for a given seed. */
function mulberry32(a) {
  return function () {
    a |= 0; a = (a + 0x6D2B79F5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

export function snapDuration(minutes) {
  return GYM_DURATIONS.reduce((best, d) => Math.abs(d - minutes) < Math.abs(best - minutes) ? d : best, GYM_DURATIONS[0]);
}

/* Build a full workout. `avoidIds` (recently-seen) are de-prioritised, `swaps`
   pins an exercise into a block index, `hard` adds a cardio finisher + density. */
export function generateGymWorkout({ minutes = 45, venue = "home", equipment = {}, banned = [],
                                     avoidIds = [], swaps = {}, hard = false, seed = 1 } = {}) {
  const dur = snapDuration(minutes);
  const slots = GYM_TEMPLATES[dur].map(([category, count]) => ({ category, count }));
  if (hard) slots.push({ category: "cardio", count: 1, finisher: true });

  const pool = filterEligible({ venue, equipment, banned });
  const byCat = {};
  for (const c of CATEGORIES) byCat[c] = pool.filter(e => e.category === c);

  const rng = mulberry32((seed >>> 0) || 1);
  const avoid = new Set(avoidIds);
  const used = new Set();

  const pick = (cat, count, bi) => {
    const chosen = [];
    const pin = swaps[bi] ? byId.get(swaps[bi]) : null;
    if (pin && pin.category === cat && !used.has(pin.id)) { chosen.push(pin); used.add(pin.id); }
    const ranked = byCat[cat]
      .filter(e => !used.has(e.id))
      .map(e => ({ e, k: rng() + (avoid.has(e.id) ? 10 : 0) }))
      .sort((a, b) => a.k - b.k)
      .map(x => x.e);
    for (const e of ranked) { if (chosen.length >= count) break; chosen.push(e); used.add(e.id); }
    return chosen;
  };

  const equipmentNeeded = new Set();
  let blocks = slots.map((slot, bi) => {
    const exs = pick(slot.category, slot.count, bi);
    exs.forEach(e => e.equipment.forEach(k => equipmentNeeded.add(k)));
    const base = exs[0] ? exs[0].defaultTiming : { rounds: 3, workSec: 40, restSec: 20 };
    return { bi, category: slot.category, rounds: base.rounds, work: base.workSec, rest: base.restSec,
             finisher: !!slot.finisher,
             exercises: exs.map(e => ({ id: e.id, name: e.name, instr: e.instr, unilateral: e.unilateral })) };
  }).filter(b => b.exercises.length);

  // fit: scale the strength/cardio blocks' rounds toward the target duration
  const est = b => b.rounds * b.exercises.length * (b.work + b.rest);
  const isFixed = b => b.category === "warmup" || b.category === "mobility";
  const fixedSec = blocks.filter(isFixed).reduce((a, b) => a + est(b), 0);
  const flex = blocks.filter(b => !isFixed(b));
  const flexSec = flex.reduce((a, b) => a + est(b), 0);
  if (flexSec > 0) {
    const ratio = Math.max(60, dur * 60 - fixedSec) / flexSec;
    for (const b of flex) {
      let r = Math.round(b.rounds * ratio);
      if (hard && (b.category === "cardio" || b.category === "lower")) { r += 1; b.rest = Math.max(10, b.rest - 5); }
      b.rounds = Math.max(2, Math.min(6, r));
    }
  }
  const estMinutes = Math.round(blocks.reduce((a, b) => a + est(b), 0) / 60);

  return { minutes: dur, venue, blocks, estMinutes,
           estIntensity: hard ? "high" : "low", equipmentNeeded: [...equipmentNeeded] };
}

/* Flatten a workout's exercise ids (for avoid-recent + ban bookkeeping). */
export function workoutExerciseIds(workout) {
  return (workout.blocks || []).flatMap(b => b.exercises.map(e => e.id));
}
